#[test]
fn test_batch_matches_individual() {
    let embedder = static_mrl_embedder();
    let texts = vec!["hello world", "foo bar", "test three"];

    let batch = embedder.embed_batch(&texts).unwrap();
    let individual: Vec<_> = texts.iter()
        .map(|t| embedder.embed(t).unwrap())
        .collect();

    for (i, (b, ind)) in batch.iter().zip(individual.iter()).enumerate() {
        let diff: f32 = b.iter().zip(ind).map(|(a, b)| (a - b).abs()).sum();
        assert!(diff < 0.001,
            "Batch and individual should match at index {}, diff={}", i, diff);
    }
}

