### Generic List Table
```rust
use rich_rust::prelude::*;
use std::cmp::Ordering;

pub struct ListTable<T: Clone> {
    items: Vec<T>,
    columns: Vec<TableColumn<T>>,
    title: String,
    theme: Theme,
    sorted_by: Option<usize>,
    sort_descending: bool,
    page_size: Option<usize>,
}

pub struct TableColumn<T> {
    name: String,
    width: Option<usize>,
    justify: JustifyMethod,
    style: Option<Style>,
    extractor: Box<dyn Fn(&T) -> String>,
    sort_key: Option<Box<dyn Fn(&T) -> i64>>,
}

impl<T> TableColumn<T> {
    pub fn new(name: &str, extractor: impl Fn(&T) -> String + 'static) -> Self {
        Self {
            name: name.to_string(),
            width: None,
            justify: JustifyMethod::Left,
            style: None,
            extractor: Box::new(extractor),
            sort_key: None,
        }
    }

    pub fn width(mut self, width: usize) -> Self {
        self.width = Some(width);
        self
    }

    pub fn justify(mut self, justify: JustifyMethod) -> Self {
        self.justify = justify;
        self
    }

    pub fn style(mut self, style: Style) -> Self {
        self.style = Some(style);
        self
    }

    pub fn sortable(mut self, key_fn: impl Fn(&T) -> i64 + 'static) -> Self {
        self.sort_key = Some(Box::new(key_fn));
        self
    }
}

impl<T: Clone> ListTable<T> {
    pub fn new(title: &str, items: Vec<T>) -> Self {
        Self {
            items,
            columns: vec![],
            title: title.to_string(),
            theme: Theme::default(),
            sorted_by: None,
            sort_descending: true,
            page_size: None,
        }
    }

    pub fn theme(mut self, theme: Theme) -> Self {
        self.theme = theme;
        self
    }

    pub fn add_column(mut self, column: TableColumn<T>) -> Self {
        self.columns.push(column);
        self
    }

    pub fn sort_by(mut self, column_idx: usize, descending: bool) -> Self {
        self.sorted_by = Some(column_idx);
        self.sort_descending = descending;
        self
    }

    pub fn page_size(mut self, size: usize) -> Self {
        self.page_size = Some(size.max(1));
        self
    }

    fn sorted_items(&self) -> Vec<T> {
        let mut items = self.items.clone();

        if let Some(col_idx) = self.sorted_by {
            if let Some(ref col) = self.columns.get(col_idx) {
                if let Some(ref sort_key) = col.sort_key {
                    items.sort_by(|a, b| {
                        let ka = sort_key(a);
                        let kb = sort_key(b);
                        if self.sort_descending {
                            kb.cmp(&ka)
                        } else {
                            ka.cmp(&kb)
                        }
                    });
                }
            }
        }

        items
    }

    pub fn render(&self, output: &Output) {
        if !output.is_styled() {
            self.render_plain(output);
            return;
        }

        self.render_styled(output);
    }

    fn render_styled(&self, output: &Output) {
        let mut table = Table::new()
            .title(&self.title);

        // Add columns
        for col in &self.columns {
            let mut column = Column::new(&col.name);
            if let Some(w) = col.width {
                column = column.width(w);
            }
            column = column.justify(col.justify.clone());
            if let Some(ref style) = col.style {
                column = column.style(style.clone());
            }
            table = table.with_column(column);
        }

        // Get sorted items (possibly paginated)
        let items = self.sorted_items();
        let display_items = if let Some(page_size) = self.page_size {
            &items[..items.len().min(page_size)]
        } else {
            &items[..]
        };

        // Add rows
        for item in display_items {
            let cells: Vec<String> = self.columns.iter()
                .map(|col| (col.extractor)(item))
                .collect();
            table.add_row_cells(cells.iter().map(|s| s.as_str()));
        }

        // Render table
        output.print_renderable(&table);

        // Footer with count
        let footer = if let Some(page_size) = self.page_size {
            if self.items.len() > page_size {
                format!("[{}]Showing {} of {} items[/]", self.theme.muted, page_size, self.items.len())
            } else {
                format!("[{}]Total: {} items[/]", self.theme.muted, self.items.len())
            }
        } else {
            format!("[{}]Total: {} items[/]", self.theme.muted, self.items.len())
        };
        output.print(&footer);
    }

    fn render_plain(&self, _output: &Output) {
        // TSV output with proper escaping
        let headers: Vec<_> = self.columns.iter().map(|c| c.name.as_str()).collect();
        println!("{}", headers.join("\t"));

        let items = self.sorted_items();
        for item in &items {
            let cells: Vec<String> = self.columns.iter()
                .map(|col| {
                    let value = (col.extractor)(item);
                    // Escape tabs and newlines in TSV
                    value.replace('\t', "\\t").replace('\n', "\\n")
                })
                .collect();
            println!("{}", cells.join("\t"));
        }
    }
}
