### Hashtag List
```rust
pub fn render_hashtag_list(hashtags: &[(String, usize)], output: &Output, theme: &Theme) {
    let max_count = hashtags.iter().map(|(_, c)| *c).max().unwrap_or(1);

    let table = ListTable::new("📌 Hashtags", hashtags.to_vec())
        .theme(theme.clone())
        .add_column(
            TableColumn::new("#", |(tag, _)| format!("#{}", tag))
                .style(Style::new().foreground(theme.hashtag))
        )
        .add_column(
            TableColumn::new("Count", |(_, count)| count.to_string())
                .justify(JustifyMethod::Right)
                .sortable(|(_, count)| *count as i64)
        )
        .add_column(
            TableColumn::new("", |(_, count)| {
                let bar_len = ((*count as f64 / max_count as f64) * 20.0) as usize;
                "█".repeat(bar_len)
            })
        )
        .sort_by(1, true); // Sort by count descending

    table.render(output);
}
